import numpy as np

def local_response_normalization(x: np.ndarray, n: int = 5, k: float = 2.0, alpha: float = 1e-4, beta: float = 0.75) -> np.ndarray:
    N, C, H, W = x.shape
    output = np.zeros_like(x)
    half_n = n // 2

    for batch in range(N):
        for c in range(C):
            c_start = max(0, c - half_n)
            c_end = min(C - 1, c + half_n)
            # Sum of squares over neighboring channels
            norm = k + alpha * sum(
                x[batch, j, :, :] ** 2
                for j in range(c_start, c_end + 1)
            )
            output[batch, c, :, :] = x[batch, c, :, :] / (norm ** beta)
    return output
